var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"베는 느낌이 없었다.","JPN":"斬った手ごたえがない。","ENG":"I felt nothing on my sword.","TWN":"感覺沒砍到。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"또 빗나가다니. 우연은 아니군.","JPN":"また避けたか。これは偶然ではないな。","ENG":"I missed it again. This is not a coincidence.","TWN":"竟然又被閃掉，看來不是運氣好。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저 사람, 움직임이 너무 빨라.","JPN":"あの人、動きが早すぎる。","ENG":"That woman is too fast.","TWN":"那個人動作好快。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"협공을 했는데도 전혀 빈틈이 없다니…….","JPN":"僕たちが挟み撃ちをしても隙がない……","ENG":"We attacked together, yet we can’t find her weakness.","TWN":"就算我們一起上，也找不到漏洞……"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이제 그만 포기하시지요.","JPN":"そろそろ諦めてはどうでしょう。","ENG":"Give up now.","TWN":"放棄吧。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"졸자를 넘어서는 것조차 버거운데, 어찌 결말을 바꾸려 하시나요?","JPN":"私を越えることすらできないのに、どうして結末を変えられると？","ENG":"Ye cannot even hit me. How do ye expect to change the coming outcome?","TWN":"你們光是要越過我都已經那麼吃力，還妄想改變結局嗎？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"무녀의 혼으로 오로치의 분노를 달래는 것은 순리이자 이치일진데.","JPN":"巫女の魂でオロチの怒りを鎮めるのは理にかなっておりますが。","ENG":"It is only right to quell the rage of Orochi with the soul of the priestess.","TWN":"用巫女的靈魂來安慰大蛇的憤怒完全是合理的。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"닥치거라!","JPN":"黙れ！","ENG":"Silence!","TWN":"你閉嘴！"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그것을 거스르려 하면, 화를 부를 뿐이랍니다.","JPN":"道理に逆らえば、災いを招くだけでございまする。","ENG":"Trying to go against it will only bring greater anger.","TWN":"違反常理只會招來禍害。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"크윽…….","JPN":"くうっ……","ENG":"Gah...","TWN":"可惡……"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……이래선 안 돼. 이대로 가다간 늦을 거야.","JPN":"……このままじゃ手遅れになってしまう。","ENG":"We can’t go on like this. We’ll be late.","TWN":"……不能這樣下去，再這樣會來不及的。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치후유! 저 사람은 내가 붙잡아 둘게! 네가 치나츠를 찾아!","JPN":"千冬！　あの人は僕に任せて！　君が千夏を探すんだ！","ENG":"Chifuyu! I’ll distract her, you go find Chinatsu!","TWN":"千冬！那個人交給我！你去找千夏！"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우왓!","JPN":"うわっ！","ENG":"Wah!","TWN":"哎呀！"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이런 공격을 막을 대책도 없으면서 자신감만 넘치시는군요.","JPN":"この程度の攻撃も防げないのに自信がおありのようですね。","ENG":"Such a confidence for a man who can’t even block her attacks.","TWN":"你連怎麼抵擋攻擊的對策都沒想好，還真是有自信呢。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……고마워.","JPN":"……ありがとう。","ENG":"Thank you very much.","TWN":"……謝謝你。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하지만 이렇게 싸워서는 너무 늦고 말아.","JPN":"でも、このままじゃ間に合わない。","ENG":"But like I said, we’ll be late if we go on like this.","TWN":"但再這樣打下去會來不及的。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};